package registry

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

const SupportedPackageAPIVersion = "1"

// ValidationIssue represents one package or plugin validation problem.
type ValidationIssue struct {
	Path    string
	Message string
}

func (i ValidationIssue) Error() string {
	if i.Path == "" {
		return i.Message
	}
	return fmt.Sprintf("%s: %s", i.Path, i.Message)
}

type packageManifestRaw struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        string         `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  any            `yaml:"api_version"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords"`
}

// knownManifestKeys is the set of top-level keys consumed by the current
// manifest schema. Any additional keys are preserved on Package.Extra so
// manifests written against newer api_versions round-trip without silent
// field loss.
var knownManifestKeys = map[string]struct{}{
	"name":        {},
	"version":     {},
	"description": {},
	"type":        {},
	"source":      {},
	"api_version": {},
	"install":     {},
	"keywords":    {},
}

// LoadPackageManifest reads and validates package.yaml from root.
func LoadPackageManifest(root string) (*Package, []ValidationIssue, error) {
	manifestPath := filepath.Join(root, "package.yaml")
	data, err := os.ReadFile(manifestPath)
	if err != nil {
		return nil, nil, err
	}

	var raw packageManifestRaw
	if err := yaml.Unmarshal(data, &raw); err != nil {
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	// Also unmarshal into a free-form map so any keys not in the typed
	// struct survive as Package.Extra. yaml.v3 returns
	// map[string]any, preserving nested structure for round-trip.
	var full map[string]any
	if err := yaml.Unmarshal(data, &full); err != nil {
		// If the typed unmarshal succeeded, this cannot realistically
		// fail — but guard anyway.
		issue := ValidationIssue{
			Path:    manifestPath,
			Message: fmt.Sprintf("invalid YAML: %v", err),
		}
		return nil, []ValidationIssue{issue}, fmt.Errorf("%s: invalid YAML: %w", manifestPath, err)
	}

	pkg, issues := validatePackageManifest(manifestPath, raw)
	if pkg != nil {
		if extra := extraManifestKeys(full); len(extra) > 0 {
			pkg.Extra = extra
		}
	}
	if len(issues) > 0 && pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	// Even when validation issues exist, return the partial package so callers
	// can perform structural audits (symlinks, SKILL.md files) independently.
	// However, if no package was returned at all, return an error so callers
	// know something is fundamentally wrong.
	if pkg == nil {
		return nil, issues, fmt.Errorf("%s: %s", manifestPath, JoinValidationIssues(issues))
	}
	return pkg, issues, nil
}

// extraManifestKeys returns manifest keys that are not part of the current
// typed schema. Values are preserved as-is so callers can inspect them later.
func extraManifestKeys(full map[string]any) map[string]any {
	if len(full) == 0 {
		return nil
	}
	var extra map[string]any
	for k, v := range full {
		if _, known := knownManifestKeys[k]; known {
			continue
		}
		if extra == nil {
			extra = make(map[string]any, len(full))
		}
		extra[k] = v
	}
	return extra
}

// LoadPackageManifestWithFallback reads package.yaml and falls back to the
// provided package when the manifest is missing.
func LoadPackageManifestWithFallback(root string, fallback *Package) (*Package, bool, []ValidationIssue, error) {
	pkg, issues, err := LoadPackageManifest(root)
	if err == nil {
		// Return issues separately even when package is valid, so callers can
		// detect schema problems while still using the package for structural audits.
		if len(issues) > 0 {
			return pkg, false, issues, nil
		}
		return pkg, false, nil, nil
	}

	// If a partial package was returned (YAML parsed but validation issues exist),
	// return it with the issues so callers can still use its structure.
	if pkg != nil {
		return pkg, false, issues, nil
	}

	if os.IsNotExist(err) {
		return fallback, true, nil, err
	}

	if fallback != nil {
		return fallback, false, issues, err
	}
	return nil, false, issues, err
}

// validatePackageManifest validates required fields and returns a partial package
// even when validation issues are found. This ensures that structural audits
// (symlinks, SKILL.md files) can proceed independently of manifest schema issues.
func validatePackageManifest(path string, raw packageManifestRaw) (*Package, []ValidationIssue) {
	var issues []ValidationIssue

	name := strings.TrimSpace(raw.Name)
	if name == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `name`"})
	}
	version := strings.TrimSpace(raw.Version)
	if version == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `version`"})
	}
	description := strings.TrimSpace(raw.Description)
	if description == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `description`"})
	}
	pkgType, ok := parseManifestPackageType(raw.Type)
	if !ok {
		issues = append(issues, ValidationIssue{Path: path, Message: fmt.Sprintf("unsupported `type` %q", strings.TrimSpace(raw.Type))})
	}
	source := strings.TrimSpace(raw.Source)
	if source == "" {
		issues = append(issues, ValidationIssue{Path: path, Message: "missing required field `source`"})
	}

	apiVersion, apiIssue := parseAPIVersion(raw.APIVersion)
	if apiIssue != "" {
		issues = append(issues, ValidationIssue{Path: path, Message: apiIssue})
	}

	// Always construct a partial package so structural audits can proceed.
	// Validation issues are still collected and returned separately.
	pkg := &Package{
		Name:        name,
		Version:     version,
		Description: description,
		Type:        pkgType,
		Source:      source,
		APIVersion:  apiVersion,
		Install:     raw.Install,
		Keywords:    append([]string(nil), raw.Keywords...),
	}
	return pkg, issues
}

func parseManifestPackageType(rawType string) (PackageType, bool) {
	switch PackageType(strings.TrimSpace(rawType)) {
	case PackageTypeWorkflow, PackageTypePlugin, PackageTypePersonaPack, PackageTypeTemplatePack:
		return PackageType(strings.TrimSpace(rawType)), true
	default:
		return "", false
	}
}

func parseAPIVersion(raw any) (string, string) {
	if raw == nil {
		return "", "missing required field `api_version`"
	}

	value := strings.TrimSpace(fmt.Sprint(raw))
	if value == "" {
		return "", "missing required field `api_version`"
	}
	if value != SupportedPackageAPIVersion {
		return value, fmt.Sprintf("unsupported `api_version` %q (supported: %s)", value, SupportedPackageAPIVersion)
	}
	return value, ""
}

}

// JoinValidationIssues renders a slice of validation issues into a single
// semicolon-separated error string.
func JoinValidationIssues(issues []ValidationIssue) string {
	msgs := make([]string, 0, len(issues))
	for _, issue := range issues {
		msgs = append(msgs, issue.Error())
	}
	return strings.Join(msgs, "; ")
}

func defaultPackageRootTarget(name string) string {
	return fmt.Sprintf(".ddx/plugins/%s", name)
}

package registry

import (
	"fmt"
	"strings"
)

// PackageType represents the type of a registry package.
type PackageType string

const (
	PackageTypeWorkflow     PackageType = "workflow"
	PackageTypePlugin       PackageType = "plugin"
	PackageTypePersonaPack  PackageType = "persona-pack"
	PackageTypeTemplatePack PackageType = "template-pack"
	PackageTypeResource     PackageType = "resource"
)

// InstallMapping describes a source→target copy during installation.
type InstallMapping struct {
	Source string `yaml:"source"`
	Target string `yaml:"target"`
}

// PackageInstall describes what to copy during installation.
type PackageInstall struct {
	Root       *InstallMapping  `yaml:"root,omitempty"`       // plugin root (e.g., .ddx/plugins/helix)
	Skills     []InstallMapping `yaml:"skills,omitempty"`     // skills directories (copied to each target)
	Scripts    *InstallMapping  `yaml:"scripts,omitempty"`    // scripts/binaries
	Symlinks   []SymlinkMapping `yaml:"symlinks,omitempty"`   // post-install symlinks
	Executable []string         `yaml:"executable,omitempty"` // paths (relative to root) that must be executable
}

// SymlinkMapping describes a symlink to create during installation.
type SymlinkMapping struct {
	Source string `yaml:"source"` // the source path (relative to install root)
	Target string `yaml:"target"` // the target path (where symlink points)
}

// Package describes a single installable package.
type Package struct {
	Name        string         `yaml:"name"`
	Version     string         `yaml:"version"`
	Description string         `yaml:"description"`
	Type        PackageType    `yaml:"type"`
	Source      string         `yaml:"source"`
	APIVersion  string         `yaml:"api_version,omitempty"`
	Install     PackageInstall `yaml:"install"`
	Keywords    []string       `yaml:"keywords,omitempty"`
	// Extra captures top-level keys not recognized by this DDx version so
	// newer manifests can keep their unknown fields in memory without
	// silently dropping them. See SD-018 "Manifest Versioning". Not
	// marshaled via `yaml:"-"` so callers must preserve it explicitly.
	Extra map[string]any `yaml:"-"`
}

// Registry holds the list of known packages.
type Registry struct {
	Packages []Package
}

// BuiltinRegistry returns the built-in registry of known packages.
func BuiltinRegistry() *Registry {
	return &Registry{
		Packages: []Package{
			{
				Name:        "ddx",
				Version:     "0.4.7",
				Description: "DDx default library: prompts, personas, MCP configs, environments, skills",
				Type:        PackageTypePlugin,
				Source:      "https://github.com/DocumentDrivenDX/ddx",
				Install: PackageInstall{
					Root: &InstallMapping{
						Source: "library",
						Target: ".ddx/plugins/ddx",
					},
					Skills: []InstallMapping{
						{Source: ".agents/skills/", Target: ".agents/skills/"},
						{Source: ".agents/skills/", Target: ".claude/skills/"},
					},
				},
				Keywords: []string{"library", "prompts", "personas", "mcp", "default", "skills"},
			},
			{
				Name:        "helix",
				Version:     "0.3.2",
				Description: "Supervisory autopilot for AI-assisted software delivery",
				Type:        PackageTypeWorkflow,
				Source:      "https://github.com/DocumentDrivenDX/helix",
				Install: PackageInstall{
					// Plugin installs are project-local (FEAT-015): the tree
					// lives under .ddx/plugins/<name>/, never in $HOME.
					Root: &InstallMapping{
						Source: ".",
						Target: ".ddx/plugins/helix",
					},
					// Skills installed to project-local skill directories.
					// skills.Install copies real files into both .agents/skills/
					// and .claude/skills/ regardless of mapping target.
					Skills: []InstallMapping{
						{Source: ".agents/skills/", Target: ".agents/skills/"},
						{Source: ".agents/skills/", Target: ".claude/skills/"},
					},
					// CLI script → ~/.local/bin/helix
					// Uses scripts/helix directly (bin/helix has a symlink
					// resolution bug when invoked through a symlink).
					Scripts: &InstallMapping{
						Source: "scripts/helix",
						Target: "~/.local/bin/helix",
					},
					Executable: []string{
						"scripts/helix",
					},
				},
				Keywords: []string{"workflow", "methodology", "ai", "development"},
			},
		},
	}
}

// Find returns the package with the given name, or an error if not found.
func (r *Registry) Find(name string) (*Package, error) {
	for i := range r.Packages {
		if r.Packages[i].Name == name {
			return &r.Packages[i], nil
		}
	}
	return nil, fmt.Errorf("package %q not found in registry", name)
}

// Search returns all packages whose name, description, or keywords contain the query.
func (r *Registry) Search(query string) []Package {
	q := strings.ToLower(query)
	var results []Package
	for _, pkg := range r.Packages {
		if matchesQuery(pkg, q) {
			results = append(results, pkg)
		}
	}
	return results
}

func matchesQuery(pkg Package, query string) bool {
	if strings.Contains(strings.ToLower(pkg.Name), query) {
		return true
	}
	if strings.Contains(strings.ToLower(pkg.Description), query) {
		return true
	}
	if strings.Contains(strings.ToLower(string(pkg.Type)), query) {
		return true
	}
	for _, kw := range pkg.Keywords {
		if strings.Contains(strings.ToLower(kw), query) {
			return true
		}
	}
	return false
}

// IsResourcePath returns true if name looks like a resource path (e.g. "persona/foo").
func IsResourcePath(name string) bool {
	return strings.Contains(name, "/")
}

package registry

import (
	"archive/tar"
	"compress/gzip"
	"fmt"
	"io"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/skills"
)

// InstallPackage downloads the source release tarball and copies declared install mappings
// into projectRoot. It records installed files (project-relative when possible) in the
// returned InstalledEntry.
func InstallPackage(pkg *Package, projectRoot string) (InstalledEntry, error) {
	entry := InstalledEntry{
		Name:        pkg.Name,
		Version:     pkg.Version,
		Type:        pkg.Type,
		Source:      pkg.Source,
		InstalledAt: time.Now(),
	}

	// FEAT-015 early validation: if the package argument already declares a
	// home-rooted Root.Target, reject it before doing any I/O. The post-
	// manifest check below covers manifest-supplied targets after download.
	if pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	// Switch into projectRoot so relative install targets resolve against the
	// project, not the caller's cwd. This keeps copyMapping, ExpandHome, and
	// the recorded entry.Files paths project-relative.
	if projectRoot != "" {
		absProject, absErr := filepath.Abs(projectRoot)
		if absErr == nil {
			if origDir, gwdErr := os.Getwd(); gwdErr == nil && origDir != absProject {
				if err := os.Chdir(absProject); err == nil {
					defer func() { _ = os.Chdir(origDir) }()
				}
			}
		}
	}

	// Download and extract the release tarball to a temp directory.
	tmpDir, err := os.MkdirTemp("", "ddx-install-"+pkg.Name+"-*")
	if err != nil {
		return entry, fmt.Errorf("creating temp dir: %w", err)
	}
	defer func() { _ = os.RemoveAll(tmpDir) }()

	tarballURL := githubTarballURL(pkg.Source, pkg.Version)
	extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
	if err != nil {
		return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
	}

	if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(extractedDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
		if manifestPkg != nil {
			pkg = manifestPkg
		}
	} else {
		if len(manifestIssues) > 0 {
			return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
		}
		return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
	}

	if pkg.Install.Root == nil {
		pkg.Install.Root = &InstallMapping{
			Source: ".",
			Target: defaultPackageRootTarget(pkg.Name),
		}
	}

	// FEAT-015: plugin install targets must be project-relative. Manifests
	// that try to write into the user's home are rejected so plugins can't
	// pollute global state.
	if strings.HasPrefix(pkg.Install.Root.Target, "~") {
		return entry, fmt.Errorf("FEAT-015: Root.Target must be project-relative; got %s in package %s; update the manifest to use a relative path", pkg.Install.Root.Target, pkg.Name)
	}

	if issues := ValidatePackageStructure(extractedDir, pkg); len(issues) > 0 {
		return entry, fmt.Errorf("validating package structure: %s", JoinValidationIssues(issues))
	}

	// Process Root mapping — copy the plugin tree into the project-local
	// install location (e.g. .ddx/plugins/<name>/).
	var installedRoot string
	files, err := copyMapping(extractedDir, pkg.Install.Root)
	if err != nil {
		return entry, fmt.Errorf("installing plugin root: %w", err)
	}
	entry.Files = append(entry.Files, files...)
	installedRoot = ExpandHome(pkg.Install.Root.Target)

	// Ensure declared executables have the execute bit set.
	for _, rel := range pkg.Install.Executable {
		p := filepath.Join(installedRoot, filepath.FromSlash(rel))
		if info, err := os.Stat(p); err == nil && !info.IsDir() {
			_ = os.Chmod(p, info.Mode()|0111)
		}
	}

	// Process Skills via the shared installer. skills.Install copies real
	// files into <projectRoot>/.agents/skills/ and <projectRoot>/.claude/skills/.
	// No symlinks are ever created — this is the cross-platform invariant
	// that FEAT-015 relies on.
	if len(pkg.Install.Skills) > 0 {
		// Use the extracted tarball as the skill source rather than the
		// post-copy installed root: copyMapping skips broken symlinks (a
		// known GitHub-tarball quirk), so the installed tree may have an
		// empty .agents/skills/. The extracted dir preserves the original
		// layout — including broken symlinks — and skills.discoverSkills
		// recovers them via the skills/<name> fallback.
		absExtracted, absErr := filepath.Abs(extractedDir)
		if absErr != nil {
			absExtracted = extractedDir
		}
		absProject, absErr := filepath.Abs(".")
		if absErr != nil {
			absProject = projectRoot
		}
		if err := skills.Install(os.DirFS(absExtracted), absProject, skills.Options{Force: true}); err != nil {
			return entry, fmt.Errorf("installing skills: %w", err)
		}
		entry.Files = append(entry.Files, recordInstalledSkills(absExtracted, absProject)...)
	}

	// Process Scripts mapping — copy the script to the target path.
	// If the target is already a symlink, the developer is managing it
	// themselves (e.g. symlink to their git checkout) — skip with a notice.
	if pkg.Install.Scripts != nil {
		dst := ExpandHome(pkg.Install.Scripts.Target)
		if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
			target, _ := os.Readlink(dst)
			fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
			entry.Files = append(entry.Files, dst)
		} else {
			srcDir := extractedDir
			if installedRoot != "" {
				srcDir = installedRoot
			}
			files, err := copyMapping(srcDir, pkg.Install.Scripts)
			if err != nil {
				return entry, fmt.Errorf("installing scripts: %w", err)
			}
			entry.Files = append(entry.Files, files...)

			// Ensure the installed script is executable.
			if info, err := os.Stat(dst); err == nil && !info.IsDir() {
				_ = os.Chmod(dst, info.Mode()|0111)
			}
		}
	}

	// Process symlinks.
	for _, sym := range pkg.Install.Symlinks {
		src := ExpandHome(sym.Source)
		dst := ExpandHome(sym.Target)

		// Create parent dir if needed.
		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
			return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
		}

		// Remove existing symlink/file if present.
		if _, err := os.Lstat(dst); err == nil {
			if err := os.RemoveAll(dst); err != nil {
				return entry, fmt.Errorf("removing existing %s: %w", dst, err)
			}
		}

		if err := os.Symlink(src, dst); err != nil {
			return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
		}
		entry.Files = append(entry.Files, dst)
	}

	return entry, nil
}

// recordInstalledSkills returns project-relative paths to the skill directories
// installed under .agents/skills/ and .claude/skills/ that came from the given
// plugin root.
func recordInstalledSkills(installedRoot, projectRoot string) []string {
	var names []string
	for _, candidate := range []string{
		filepath.Join(installedRoot, ".agents", "skills"),
		filepath.Join(installedRoot, "skills"),
	} {
		entries, err := os.ReadDir(candidate)
		if err != nil {
			continue
		}
		for _, e := range entries {
			if e.IsDir() || e.Type()&os.ModeSymlink != 0 {
				names = append(names, e.Name())
			}
		}
		if len(names) > 0 {
			break
		}
	}

	var files []string
	for _, name := range names {
		for _, sub := range []string{".agents/skills", ".claude/skills"} {
			rel := filepath.Join(filepath.FromSlash(sub), name)
			files = append(files, rel)
		}
	}
	return files
}

// InstallResource installs a single resource file (e.g. "persona/strict-code-reviewer")
// from the ddx-library GitHub repo into the local .ddx/plugins/ddx/<type>/ directory.
func InstallResource(resourcePath string) (InstalledEntry, error) {
	entry := InstalledEntry{
		Name:        resourcePath,
		Version:     "latest",
		Type:        PackageTypeResource,
		Source:      "https://github.com/DocumentDrivenDX/ddx-library",
		InstalledAt: time.Now(),
	}

	// resourcePath is like "persona/strict-code-reviewer"
	parts := strings.SplitN(resourcePath, "/", 2)
	if len(parts) != 2 {
		return entry, fmt.Errorf("invalid resource path %q: expected <type>/<name>", resourcePath)
	}
	resourceType, resourceName := parts[0], parts[1]

	// Determine target directory relative to cwd.
	target := filepath.Join(".ddx", "plugins", "ddx", resourceType+"s")
	if err := os.MkdirAll(target, 0755); err != nil {
		return entry, fmt.Errorf("creating target directory %s: %w", target, err)
	}

	// Fetch raw file from GitHub.
	rawURL := fmt.Sprintf(
		"https://raw.githubusercontent.com/easel/ddx-library/main/%ss/%s.md",
		resourceType, resourceName,
	)

	destFile := filepath.Join(target, resourceName+".md")
	if err := downloadFile(rawURL, destFile); err != nil {
		return entry, fmt.Errorf("downloading %s: %w", rawURL, err)
	}

	entry.Files = append(entry.Files, destFile)
	return entry, nil
}

